from cryptography.fernet import Fernet
from django.conf import settings
from django.db import models

class FernetProvider:
    def __init__(self):
        self.key = settings.MASTER_KEY
        self.cipher_suite = Fernet(self.key)

    def encrypt(self, plaintext):
        return self.cipher_suite.encrypt(plaintext)

    def decrypt(self, ciphertext):
        return self.cipher_suite.decrypt(ciphertext)

class MasterKeyManager:
    @staticmethod
    def get_cipher_suite():
        return FernetProvider()

class EncryptionManager:
    @staticmethod
    def encrypt(data):
        cipher_suite = MasterKeyManager.get_cipher_suite()
        return cipher_suite.encrypt(data)

class DecryptionManager:
    @staticmethod
    def decrypt(data):
        cipher_suite = MasterKeyManager.get_cipher_suite()
        return cipher_suite.decrypt(data)

class TOTPDevice(models.Model):
