    def save(self, *args, **kwargs):
        super().save(*args, **kwargs)
        if self.pk:  # Only encrypt if the object is already saved (has a primary key)
            self.key = EncryptionManager.encrypt(self.key)

    @property
    def key(self):
        key = super().key
        return DecryptionManager.decrypt(key)

    @key.setter
    def key(self, value):
        super().key = EncryptionManager.encrypt(value)
